module RefModule (D, CLK, LOAD, Q);
input [3:0] D;
input CLK, LOAD;
output Q;
reg [3:0] unused_shift_reg;

always @(posedge CLK) begin
    if (LOAD)
        unused_shift_reg <= D;
    else
        unused_shift_reg <= {1'b0, unused_shift_reg[3:1]};
end

assign Q = unused_shift_reg[0];

endmodule
